const raw = $input.item.json;
const clinics = Array.isArray(raw) ? raw : [raw];
return clinics.filter(c => c && c.id).map(c => ({ json: c }));

const clinicData = $('Split Clinics').item.json;
const clinicId = clinicData.id;

const convItems = $input.all();
const convs = convItems.map(i => i.json);

const today = new Date().toISOString().split('T')[0];

let newLeads = 0, hot = 0, warm = 0, cold = 0, handoffs = 0, totalScore = 0, count = 0;

for (const c of convs) {
  if (!c) continue;

  if (c.created_at && c.created_at.startsWith(today)) newLeads++;

  count++;

  const s = c.lead_score || 0;
  totalScore += s;

  if (s >= 70) hot++;
  else if (s >= 40) warm++;
  else cold++;

  if (c.handoff_triggered) handoffs++;
}

return [{
  json: {
    clinic_id: clinicId,
    clinic_name: clinicData.name || '',
    clinic_email: clinicData.email || null,
    lead_doctor_name: clinicData.lead_doctor_name || null,
    date: today,
    new_conversations: newLeads,
    hot_leads: hot,
    warm_leads: warm,
    cold_leads: cold,
    handed_off_leads: handoffs,
    avg_lead_score: count > 0 ? parseFloat((totalScore / count).toFixed(2)) : 0
  }
}];

const s = $('Calculate Stats').item.json;
const clinicName = s.clinic_name || 'Klinik';
const doctorName = s.lead_doctor_name ? `Dr. ${s.lead_doctor_name}` : '';
const dateStr = new Date().toLocaleDateString('tr-TR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const scoreColor = s.avg_lead_score >= 70 ? '#dc2626' :
  s.avg_lead_score >= 40 ? '#d97706' : '#3b82f6';

const summaryParts = [];
summaryParts.push(`Bugün <strong>${s.new_conversations}</strong> yeni konuşma başladı.`);
if (s.hot_leads > 0) summaryParts.push(`<strong style="color:#dc2626">${s.hot_leads} hot lead 🔥</strong> sıcak fırsata dönüştü.`);
else summaryParts.push('Hot lead oluşmadı.');
if (s.handed_off_leads > 0) summaryParts.push(`<strong>${s.handed_off_leads}</strong> konuşma satış ekibine devredildi.`);
else summaryParts.push('Otomatik devir yapılmadı.');
summaryParts.push(`Ortalama lead skoru: <strong style="color:${scoreColor}">${s.avg_lead_score}/100</strong>.`);

const html = `<!DOCTYPE html>
<html lang="tr">
<head><meta charset="UTF-8">
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;background:#f1f5f9;padding:24px}
.wrap{max-width:560px;margin:0 auto}
.head{background:linear-gradient(135deg,#1e40af 0%,#3b82f6 100%);color:#fff;padding:28px 24px;border-radius:14px 14px 0 0}
.head h1{font-size:20px;font-weight:700;margin-bottom:4px}
.head p{font-size:12px;opacity:.85}
.body{background:#fff;padding:24px;border:1px solid #e2e8f0;border-top:0}
.summary{background:#eff6ff;border:1px solid #bfdbfe;border-radius:10px;padding:16px 18px;margin-bottom:20px;font-size:13.5px;color:#1e3a8a;line-height:1.8}
.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:4px}
.card{border:1px solid #e2e8f0;border-radius:10px;padding:14px 10px;text-align:center}
.num{font-size:28px;font-weight:800;line-height:1}
.lbl{font-size:11px;color:#64748b;margin-top:5px}
.foot{background:#f8fafc;border:1px solid #e2e8f0;border-top:0;padding:14px 24px;border-radius:0 0 14px 14px;text-align:center;font-size:11px;color:#94a3b8}
.foot a{color:#3b82f6;text-decoration:none}
</style></head>
<body><div class="wrap">
  <div class="head">
    <h1>📊 Günlük AI Asistan Raporu</h1>
    <p>${clinicName}${doctorName ? ' &middot; ' + doctorName : ''} &middot; ${dateStr}</p>
  </div>
  <div class="body">
    <div class="summary">${summaryParts.join(' ')}</div>
    <div class="grid">
      <div class="card">
        <div class="num" style="color:#1e40af">${s.new_conversations}</div>
        <div class="lbl">🆕 Yeni Konuşma</div>
      </div>
      <div class="card" style="border-left:3px solid #ef4444">
        <div class="num" style="color:#dc2626">${s.hot_leads}</div>
        <div class="lbl">🔥 Hot Lead (&ge;70)</div>
      </div>
      <div class="card" style="border-left:3px solid #f59e0b">
        <div class="num" style="color:#d97706">${s.warm_leads}</div>
        <div class="lbl">🌡️ Warm Lead (40-69)</div>
      </div>
      <div class="card" style="border-left:3px solid #3b82f6">
        <div class="num" style="color:#3b82f6">${s.cold_leads}</div>
        <div class="lbl">❄️ Cold Lead (&lt;40)</div>
      </div>
      <div class="card" style="border-left:3px solid #10b981">
        <div class="num" style="color:#059669">${s.handed_off_leads}</div>
        <div class="lbl">🤝 Handoff</div>
      </div>
      <div class="card" style="border-left:3px solid #8b5cf6">
        <div class="num" style="color:${scoreColor}">${s.avg_lead_score}</div>
        <div class="lbl">📈 Ort. Lead Skoru</div>
      </div>
    </div>
  </div>
  <div class="foot">
    Bu rapor <strong>stoaix AI Asistan</strong> tarafından otomatik oluşturulmuştur.<br>
    <a href="https://panel.stoaix.com">panel.stoaix.com</a>'dan detaylı analitiğe ulaşabilirsiniz.
  </div>
</div></body></html>`;

return [{
  json: {
    to: s.clinic_email || 'admin@stoaix.com',
    subject: `📊 Günlük AI Raporu – ${clinicName} – ${new Date().toLocaleDateString('tr-TR')}`,
    html
  }
}];
